USE asset_mgm;
SET NAMES utf8mb4;
SET FOREIGN_KEY_CHECKS=0;

DELETE FROM inspection_record WHERE description LIKE 'MOCK:%' OR task_id IN (SELECT id FROM inspection_task WHERE task_no LIKE 'IT-MOCK-%') OR asset_id IN (SELECT id FROM physical_asset WHERE asset_no LIKE 'PA-MOCK-%');
DELETE FROM inventory_detail WHERE remark LIKE 'MOCK:%' OR task_id IN (SELECT id FROM inventory_task WHERE task_no LIKE 'INV-MOCK-%');
DELETE FROM maintenance_order WHERE order_no LIKE 'MO-MOCK-%';
DELETE FROM inspection_task WHERE task_no LIKE 'IT-MOCK-%';
DELETE FROM inventory_task WHERE task_no LIKE 'INV-MOCK-%';
DELETE FROM digital_asset_access WHERE asset_id IN (SELECT id FROM digital_asset WHERE asset_no LIKE 'DA-MOCK-%');
DELETE FROM digital_asset_lineage WHERE source_asset_id IN (SELECT id FROM digital_asset WHERE asset_no LIKE 'DA-MOCK-%') OR target_asset_id IN (SELECT id FROM digital_asset WHERE asset_no LIKE 'DA-MOCK-%');
DELETE FROM digital_asset_file_version WHERE file_asset_id IN (SELECT id FROM digital_asset_file WHERE asset_id IN (SELECT id FROM digital_asset WHERE asset_no LIKE 'DA-MOCK-%'));
DELETE FROM digital_asset_file WHERE asset_id IN (SELECT id FROM digital_asset WHERE asset_no LIKE 'DA-MOCK-%');
DELETE FROM digital_asset_api WHERE asset_id IN (SELECT id FROM digital_asset WHERE asset_no LIKE 'DA-MOCK-%');
DELETE FROM digital_asset_table WHERE asset_id IN (SELECT id FROM digital_asset WHERE asset_no LIKE 'DA-MOCK-%');
DELETE FROM digital_asset_database WHERE asset_id IN (SELECT id FROM digital_asset WHERE asset_no LIKE 'DA-MOCK-%');
DELETE FROM physical_asset WHERE asset_no LIKE 'PA-MOCK-%';
DELETE FROM digital_asset WHERE asset_no LIKE 'DA-MOCK-%';
DELETE FROM project WHERE project_no LIKE 'PRJ-MOCK-%';
DELETE FROM asset_location WHERE loc_name LIKE 'MOCK-B%';
DELETE FROM sys_user_role WHERE user_id IN (SELECT id FROM sys_user WHERE username LIKE 'mock_user_%');
DELETE FROM sys_user WHERE username LIKE 'mock_user_%';
DELETE FROM sys_role WHERE role_code LIKE 'MOCK_%';

SET FOREIGN_KEY_CHECKS=1;
SELECT 'project_mock' AS item, COUNT(*) AS cnt FROM project WHERE project_no LIKE 'PRJ-MOCK-%' UNION ALL SELECT 'physical_asset_mock', COUNT(*) FROM physical_asset WHERE asset_no LIKE 'PA-MOCK-%' UNION ALL SELECT 'digital_asset_mock', COUNT(*) FROM digital_asset WHERE asset_no LIKE 'DA-MOCK-%' UNION ALL SELECT 'inspection_task_mock', COUNT(*) FROM inspection_task WHERE task_no LIKE 'IT-MOCK-%' UNION ALL SELECT 'inspection_record_mock', COUNT(*) FROM inspection_record WHERE description LIKE 'MOCK:%' UNION ALL SELECT 'maintenance_order_mock', COUNT(*) FROM maintenance_order WHERE order_no LIKE 'MO-MOCK-%' UNION ALL SELECT 'inventory_task_mock', COUNT(*) FROM inventory_task WHERE task_no LIKE 'INV-MOCK-%' UNION ALL SELECT 'inventory_detail_mock', COUNT(*) FROM inventory_detail WHERE remark LIKE 'MOCK:%' UNION ALL SELECT 'users_mock', COUNT(*) FROM sys_user WHERE username LIKE 'mock_user_%';

